var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"쳇, 꽤 하잖아?","JPN":"ちっ、やるじゃない。","ENG":"Tch. You're pretty good, I'll give you that.","TWN":"嘖，還挺厲害的嘛？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이래서 성황청의 미친개들이랑 엮이고 싶지 않았는데……!","JPN":"これだから聖皇庁の狂犬どもとは関わりたくなかったのに……！","ENG":"This's exactly why I never wanted to get involved with the Holy Curia's mad dogs...","TWN":"所以我才不想跟聖皇廳的瘋狗扯上關係……！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"닥치세요, 이단자!","JPN":"黙りなさい、異端者！","ENG":"Shut up, heretic!","TWN":"閉嘴吧，異端者！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"마지막 경고입니다. 그 변절자를 처단하지 못하면, 많은 사람들이 다칠 거예요!","JPN":"最後の警告です。あの変節者を処断しなければ、大勢の人に危害が及びます！","ENG":"This is your final warning. If we fail to execute that betrayer, many people will be hurt.","TWN":"這是最後警告。如果無法阻止那個叛徒，會有很多人受傷！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이단이라고 해도, 주님을 모시는 사제가 그걸 두고 볼 셈인가요?","JPN":"異端とはいえ主に仕える司祭が、それを傍観するつもりですか？","ENG":"Even if they are heretics, are you saying a priest who serves the Lord will simply stand by and watch?","TWN":"就算是異端，侍奉主的司祭也打算坐視不管嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"글쎄, 시장을 보니, 우리 주님께서는 별 반응이 없으시네.","JPN":"さあ、市場を見た感じ、金が転がり込む予兆はないみたいね。","ENG":"Well, judging by the market, our Lord does not seem to be reacting much.","TWN":"嗯，看看市場走勢，我們的主似乎沒什麼反應呢。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L16_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"예전부터 샤레이드 테마주는 조금 떨어질 필요가 있다고 생각했거든.","JPN":"前からシャレードの価値はちょっと過大評価されてると思ってたんだけど。","ENG":"I've always thought Charade-related stocks needed to drop a bit anyway.","TWN":"我早就覺得查雷德的概念股該跌一點了。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"무슨 소리죠, 테마주?","JPN":"何を言っているんですか？　価値？","ENG":"Stocks? What are you talking about?","TWN":"你在說什麼？概念股？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아, 내가 얘기 안 했나? 내가 믿는 주님은 주식님이라서~","JPN":"あ、言ってなかった？　私の信じる主はお金だからね～","ENG":"Oh, did I not mention? The only \\"Lord\\" I believe in is money.","TWN":"啊，我沒說過嗎？我信奉的主是股神喔～"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이 세상에서 오병이어의 기적을 행사할 수 있는 건, 오직 주식뿐이라고?","JPN":"この世界で5つのパンと2匹の魚の奇跡を起こせるのは、金だけだよ？","ENG":"The only thing in this world that can perform the miracle of feeding the multitudes is stocks, you know.","TWN":"這世上能施展五餅二魚奇蹟的，只有股票不是嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"주식님? 이 무슨 불경한……!","JPN":"金？　なんと不敬な……！","ENG":"Money? What kind of blasphemy is this...?!","TWN":"股神？這是何等褻瀆……！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 이 톱날들은……?","JPN":"な、何？　このチェーンソー……？","ENG":"W-what? Saw blades...?","TWN":"什、什麼？這些鋸齒是……？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_CHAINSAW_ATTACK_SMALL"},{"id":"L23_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"돈 뜯으러 온 빚쟁이 마냥 계속 따라붙잖아?","JPN":"借金取りみたいにつきまとってくる！","ENG":"They keep chasing me like debt collectors coming to squeeze money out of me.","TWN":"跟討債的一樣一直追著不放耶？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L25_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"그야 내 체인소는 한 번 발사된 이상, 절대 멈추지 않으니까.","JPN":"アタシのチェーンソーは一度発射したら絶対止まらないから。","ENG":"Once my chainsaw is fired, it never stops.","TWN":"因為我的鏈鋸一旦射出，就絕對不會停下來。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"팔다리 몽땅 갈리고 싶지 않으면 꺼져, 이 반푼이들아.","JPN":"四肢を切り刻まれたくなければさっさと失せろ、雑魚ども。","ENG":"If you don't want all your limbs shredded, get lost, you halfwits.","TWN":"不想手腳全被絞碎就滾開，你們這群半吊子。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"헷, 꼬맹이 주제에 살벌하잖아?","JPN":"はっ、ガキのくせに殺気立っちゃって。","ENG":"Heh, pretty vicious for a kid, no?","TWN":"哼，小鬼還挺兇的嘛？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L29_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하지만 우리 꼬맹이도 맛탱이 간 걸로는 어디서 꿀리지 않는다고!","JPN":"でも、うちのガキもイカれ具合なら負けないから！","ENG":"But our kid isn't lacking when it comes to being completely unhinged either.","TWN":"不過我們家的小鬼在瘋狂程度上可不輸任何人！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"지금이야, 카타리나……!","JPN":"今だよ、カタリナ……！","ENG":"Now, Katharina...!","TWN":"就是現在，卡特莉娜……！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L33_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"알고 있다고요, 불량식품!","JPN":"わかってます、お菓子さん！","ENG":"I know, Junk food!","TWN":"我知道啦，垃圾食物！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"침식체? 잘 됐네! 써는 맛이 있겠는데!","JPN":"侵食体？　いいね。切り甲斐がありそうだ！","ENG":"A C.O.? Perfect! That should be fun to carve up!","TWN":"侵蝕體？太好了！切起來一定很爽！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_CHAINSAW_ATTACK_SMALL"},{"id":"L37_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"물러나세요, 시스터 루퍼!","JPN":"下がりなさい、シスター・ルーパー！","ENG":"Fall back, Sister Looper!","TWN":"退下，洛珀姐妹！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"게티아로 불러낸 것들은 물리적인 실체가 없는 영체예요!","JPN":"ゴエティアで呼び出したものは、実体を持たない霊体です！","ENG":"The ones summoned by Goetia are incorporeal spirits without physical bodies!","TWN":"用巫術書召喚出來的是沒有實際實體的靈體！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신 카운터 능력과는 상성이 안 맞습니다!","JPN":"あなたのカウンター能力とは相性が良くありません！","ENG":"They are a terrible match for your Counter abilities!","TWN":"和你的制裁者能力不相容！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"에잇, 그딴 거 몰라……!","JPN":"ええいっ、そんなもん知るか……！","ENG":"Damn it, I don't care about that...!","TWN":"吵死了，我才不管那種事……！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"큿, 하여간 당신은……!","JPN":"くっ、あなたって人は……！","ENG":"Honestly, you really are–!","TWN":"嘖，你這人真是……！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"게, 게티아가 갑자기 닫히다니……?","JPN":"ゴ、ゴエティアが急に閉じた……？","ENG":"W-why did Goetia suddenly close...?","TWN":"巫、巫術書竟然突然關閉了……？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L50_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"성황청 비밀 서고에는 수많은 <color=#ffd34c>금서</color>가 존재하죠.","JPN":"聖皇庁の秘密書庫には数多くの<color=#ffd34c>禁書</color>が存在します。","ENG":"There are countless <color=#ffd34c>forbidden books</color> in the Holy Curia's secret library.","TWN":"聖皇廳的祕密書庫中，收藏著無數<color=#ffd34c>禁書</color>。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그 금서에는 저마다 위험한 능력이 잠들어 있지만…….","JPN":"それぞれの禁書には危険な能力が眠っていますが……","ENG":"Each of them holds a dangerous power...","TWN":"那些禁書各自封印著危險的能力……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"<color=#ffd34c>종이</color>로 된 책인 이상, 제 능력에서 벗어날 수 없어요.","JPN":"<color=#ffd34c>紙</color>でできた本である以上、私の能力からは逃れられません。","ENG":"But as long as they are books made of <color=#ffd34c>paper</color>, they cannot escape my ability.","TWN":"但只要是<color=#ffd34c>紙張</color>構成的書，就無法脫離我的能力。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그것이 제가 비밀 서고의 사서였던 이유입니다.","JPN":"他でもない私が、秘密書庫の司書である理由です。","ENG":"That is why I was the librarian of that place.","TWN":"這正是我曾為祕密書庫圖書管理員的理由。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"크윽……!","JPN":"くっ……！","ENG":"Kgh...!","TWN":"唔……！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"어쩐지 낯이 익다 싶었는데, 이제야 알겠군요.","JPN":"どおりで見覚えのある顔だと思いましたが、やっとわかりました。","ENG":"I thought you looked familiar. Now I see why.","TWN":"難怪總覺得眼熟，現在我終於明白了。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신, 성황청의 견습 수녀로군요.","JPN":"あなた、聖皇庁の見習いシスターですね。","ENG":"You are an apprentice nun of the Holy Curia.","TWN":"你，是聖皇廳的實習修女吧。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"주를 모시는 수녀가 어째서 변절자에게 협력하는 거죠?","JPN":"主に仕えるシスターが、なぜ変節者に協力するのですか？","ENG":"Why would a nun who serves the Lord cooperate with a betrayer?","TWN":"侍奉主的修女，為何要協助叛徒？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"애초에 왜 이단자가 된 겁니까?","JPN":"そもそも、なぜ異端者になったのですか？","ENG":"To begin with, why did you become a heretic?","TWN":"你當初又為什麼會成為異端？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"제가 성황청에 들어온 이유는 저주 때문이었어요.","JPN":"私が聖皇庁に入ったのは呪いのせいでした。","ENG":"The reason I entered the Holy Curia was because of a curse.","TWN":"我是因為詛咒才進入聖皇廳。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"타인의 피밖에 마실 수 없는 몸이 되어버린 뒤, 제가 알게 된 건…….","JPN":"他人の血しか飲めない体になった後、私が気づいたのは……","ENG":"After my body became one that could only drink the blood of others, I realized something...","TWN":"在變成只能飲用他人鮮血的身體後，我明白的事是……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하늘의 계신 주께서는 그 누구도 구원하지 않는 다는 것이었죠.","JPN":"天にまします主は誰も救ってくださらないということです。","ENG":"That the Lord in the heavens saves no one at all.","TWN":"天上的主，從未拯救過任何人。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"지금 이 순간에도 조금씩 세상은 멸망을 향해 다가가고 있다.","JPN":"今この瞬間にも世界は少しずつ滅亡に近づいている。","ENG":"The end of the world is slowly approaching even as we speak.","TWN":"即使是現在，世界也朝著滅亡更近一步。"},"stage":{"bg":"HALL","bgm":"THEMA_CA_BLUE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"마음만 먹으면 이 세계를 박살내어 버릴 존재들이 심연 속에서 때를 기다리고 있지.","JPN":"その気になれば、この世界を壊せる存在が深淵の中で時を待っているのだ。","ENG":"In the depths of the abyss, there are unimaginable beings that could destroy this world on a whim.","TWN":"只要下定決心，就可以將世界毀滅掉的存在，正在深淵裡伺機而動。"},"stage":{"bg":"HALL","bgm":"THEMA_CA_BLUE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그런데 우리의 신은 무엇을 하고 있지?","JPN":"それなのに私たちの神は何をしている？","ENG":"But what is \\"our\\" God doing?","TWN":"但我們的神有什麼作為呢？"},"stage":{"bg":"HALL","bgm":"THEMA_CA_BLUE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"……그리고 신의 대리인을 자청하며 거들먹거리던 우리 사제들은?","JPN":"……そして神の代理人を自称しながら偉ぶっていた私たち司祭は？","ENG":"And what about our arrogant priests who call themselves the messengers of God?","TWN":"……還有那些以神的代言人自居，而得意洋洋的祭司們呢？"},"stage":{"bg":"HALL","bgm":"THEMA_CA_BLUE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하지만 신부님께서는 말씀하셨어요.","JPN":"でも神父様はおっしゃいました。","ENG":"But Father said this.","TWN":"但神父對我說。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"우리를 구원할 수 있는 건, 우리 스스로 밖에 없다고.","JPN":"私たちを救えるのは、私たち自身だけだと。","ENG":"That the only ones who can save us are ourselves.","TWN":"能夠拯救我們的，只有我們自己而已。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"불량식품은 몰라도 저는 그 말을 믿어요. 그러니까……","JPN":"お菓子さんはともかく、私はその言葉を信じます。だから……","ENG":"I don't know about Junk food, but I believe those words. So...","TWN":"垃圾食物怎麼想我不管，但我相信這句話。所以……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_BLUE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"음!?","JPN":"ん！？","ENG":"Mm?!","TWN":"嗯！？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_45"},{"id":"L34_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"카타리나, 하늘을 봐……!","JPN":"カタリナ、空を見て……！","ENG":"Katharina, look at the sky...!","TWN":"卡塔莉娜，你看天空……！"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저건……?","JPN":"あれは……？","ENG":"What...?","TWN":"那是……？"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"<color=#ffd34c>고래</color>잖아요…? 고래가 왜 하늘에……?","JPN":"<color=#ffd34c>クジラ</color>……？　どうして空にクジラが……？","ENG":"A <color=#ffd34c>whale</color>...? Why is that in the sky...?","TWN":"<color=#ffd34c>鯨魚</color>……？為什麼鯨魚會在天上……？"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_46"},{"id":"L40_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"저 침식체는 설마……!?","JPN":"あの侵食体は、まさか……！？","ENG":"Could that C.O. be...?!","TWN":"那個侵蝕體難道是……！？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L43_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"시스터 루퍼, 서두르죠! 어서 변절자를 막아야 합니다……!","JPN":"シスター・ルーパー、急ぎましょう！　早く変節者を阻止せねば……！","ENG":"Sister Looper, hurry! We must stop the betrayer at once...!","TWN":"洛珀姐妹，快點！一定要阻止那個叛徒……！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그렇지 않으면, 돌이킬 수 없는 사태가 벌어질 거예요!","JPN":"さもないと、取り返しのつかない事態になります！","ENG":"Otherwise, something irreversible will happen!","TWN":"不然事情會變成無法挽回的局面！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신들도 눈이 있다면, 똑똑히 보세요!","JPN":"あなたたちもその目で見なさい！","ENG":"If you have eyes, then look carefully!","TWN":"你們要是有眼睛，就給我看清楚！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L47_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그자가 초래한 이 상황, 대체 그 어디에 구원이 있다는 거죠?","JPN":"あの男が呼び寄せたこの状況のどこに救いがあるというのですか？","ENG":"In this situation he has brought about, where exactly is salvation supposed to be?","TWN":"他引發的這一切，到底是救贖？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"쳇, 그딴 거 우리가……!","JPN":"ちっ、そんなもん私たちには……！","ENG":"Tch, like we would...!","TWN":"嘖，那種事我們……！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_04"},{"id":"L50_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"그냥 보내줘, 멍멍이.","JPN":"通してあげて、ワンちゃん。","ENG":"Just let him go, Puppy.","TWN":"……放我們走吧，狗狗。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L1_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"언니? 보내 주라니 무슨 소리예요?","JPN":"姉さん？　通してあげてって、どういうことですか？","ENG":"Sis? What do you mean, let him go?","TWN":"姐姐？放我們走是什麼意思？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"상황이 바뀌었어. 신부님도 일이 잘 안 풀렸나 보네~","JPN":"状況が変わったわ。神父様のほうも上手くいかなかったみたいね～","ENG":"The situation has changed. Looks like things did not go well for Father either.","TWN":"情況變了。看來神父那邊也不太順利呢～"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"설마, 학회 영지에서 그 <color=#ffd34c>카드</color>를 꺼낼 줄이야.","JPN":"まさか学会の領地であの<color=#ffd34c>切り札</color>を出すとは。","ENG":"I never thought he would play that <color=#ffd34c>card</color> within the Society's estate.","TWN":"你該不會想在學會的領地裡打出那張<color=#ffd34c>牌</color>吧？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"카드라니… 저 고래를 말하는 거예요?","JPN":"切り札って……あのクジラのことですか？","ENG":"Card...? You mean that whale?","TWN":"牌……你是說那隻鯨魚嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"맞아. 저걸 불러낸 순간, 우리는 신부님을 도울 명분이 사라지거든.","JPN":"そう。あれを呼び出した時点で、私たちが神父様に協力する理由はなくなるの。","ENG":"That's right. The moment he summoned it, we lost any justification to help Father.","TWN":"沒錯。一旦召喚那個東西，我們就失去了幫助神父的理由。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"애초부터 그런 <color=#ffd34c>계약</color>이었으니까.","JPN":"最初からそういう<color=#ffd34c>契約</color>だったからね。","ENG":"That was the <color=#ffd34c>contract</color> from the start.","TWN":"從一開始<color=#ffd34c>契約</color>就是這樣寫的。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"계약이라고요……?","JPN":"契約……？","ENG":"Contract...?","TWN":"契約……？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"지금부터 너희는 법학부장을 도와서 저걸 토벌하도록 해.","JPN":"今からあなたたちは法学部長を手伝って、あれを討伐しなさい。","ENG":"From here on out, help the Dean of Law and take that thing down.","TWN":"從現在開始，你們去協助法學院院長討伐那個東西。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"의심당하지 않으려면, 공로를 세워야 할 거야.","JPN":"疑われないためには功績を上げたほうがいいわ。","ENG":"If you don't want to be suspected, you will need to earn some credit.","TWN":"要是不想被懷疑，就得立下功勞才行。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"잘 할 수 있겠지, 우리 멍멍이~?","JPN":"できるわよね、ワンちゃん～？","ENG":"You can handle that, right, Puppy?","TWN":"辦得到吧？我們狗狗～？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"나 참, 귀찮게시리.","JPN":"まったく、面倒くさい。","ENG":"Ugh, what a pain.","TWN":"嘖，真麻煩。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"언니, 대체 저 고래가 뭔데요?","JPN":"姉さん、いったいなんなんですか？　あのクジラ。","ENG":"Sis, just what is that whale anyway?","TWN":"姐姐，那隻鯨魚到底是什麼？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"subtitle","speaker":null,"text":{"KOREA":"전조 프로토콜 45분 전","JPN":"前兆プロトコル45分前","ENG":"45 minutes before the Omen Protocol","TWN":"前兆協議45分鐘前"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color> 관리국 본부","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>管理局本部","ENG":"Administration Direct-Control City, <color=#ffd34c>Charade</color> Administration HQ","TWN":"管理局直轄城市<color=#ffd34c>查雷德</color>管理局本部"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그게 무슨 소리야? 5종 침식체라니?","JPN":"どういうことだ？　第5種侵食体だと？","ENG":"Are you serious? It's a Category 5 C.O.?","TWN":"那是什麼意思？第5類侵蝕體？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L29_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"아무리 대균열 영향권이라고 해도, 느닷없이 5종이 나타날 리 없잖아?","JPN":"いくら大亀裂の影響圏内とはいえ、いきなり第5種が現れるわけがないだろう！","ENG":"Even within the Grand Dimension Crevice, there's no way a Category 5 would suddenly appear.","TWN":"就算在大峽谷影響範圍內，也不可能突然冒出第5類吧？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"현재 관측 장비와 데이터를 확인하고 있습니다만…….","JPN":"現在観測装備とデータを確認中ですが……","ENG":"We are currently reviewing the observation equipment and data...","TWN":"雖然目前正在確認觀測設備與數據……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"침식 현상은 언제나 예외가 있을 수 있다고, 베르너 시니어님께서…….","JPN":"侵食現象には常に例外があると、シニア・ベルナーが……","ENG":"However, Senior Werner did say that the Counterside Effect can always involve exceptions...","TWN":"但侵蝕現象本來就有例外，韋爾納Senior……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"알겠어. 그쪽 공인 카운터한테는 연락한 거지?","JPN":"ふう……わかった。そちらの公認カウンターには連絡したんだな？","ENG":"All right. You contacted the Official Counter on site, right?","TWN":"知道了。已經聯絡那邊認證的制裁者了嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그게… 오지만디아스님께서는 연락두절 상태입니다.","JPN":"それが……オジマンディアス様とは連絡がつかない状態です。","ENG":"Well... Miss Ozymandias is currently unreachable.","TWN":"那個……目前聯絡不上奧茲曼迪亞斯。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"큭, 오지만디아스……!","JPN":"くっ、オジマンディアス……！","ENG":"Kgh, Ozymandias...!","TWN":"嘖，奧茲曼迪亞斯……！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"시그니처 타입 확인 완료. 어라, 이 데이터는……?","JPN":"シグネチャータイプ確認完了。あれ？　このデータは……？","ENG":"Signature type confirmed. Huh? This data is...","TWN":"標誌類型確認完成。咦，這個數據是……？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L37_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"왜 그래?","JPN":"どうした？","ENG":"What is it?","TWN":"怎麼了？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"이 데이터, 로터스 관리국에서 한 차례 토벌된 기록이 있는 침식체입니다.","JPN":"この侵食体、ロータス管理局で一度討伐した記録があります。","ENG":"This C.O. has a record of having been neutralized once by the Lotus Administration.","TWN":"這是曾在洛德斯管理局被討伐過的侵蝕體。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"식별명, <color=#ffd34c>바루나스트라</color>……?","JPN":"識別名、<color=#ffd34c>ヴァルナストラ</color>……？","ENG":"Code Name: <color=#ffd34c>Varunastra</color>...?","TWN":"識別名稱，<color=#ffd34c>伐樓拿之艦</color>……？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"스승에게 말로만 들었지 실제로 보는 건 처음이야.","JPN":"師匠から話で聞いただけで、実際見るのは初めてだ。","ENG":"I had only heard about it from my mentor. This is my first time seeing it in person.","TWN":"我只聽師父提過，這還是第一次親眼見到。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L47_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"도시 하나가 사람들의 기억에서 통째로 사라진 기이한 사건, 대환류…….","JPN":"1つの都市が人々の記憶からまるごと消えた奇妙な事件、大還流……","ENG":"The bizarre incident where an entire city vanished from people's memories, the Great Gyre...","TWN":"整座城市從人們記憶中消失的奇異事件，大環流……"},"stage":{"bg":"VARUNA_04_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"20년 전, 로터스에서 있었던 불완전한 의식의 결과물이로군.","JPN":"20年前、ロータスで行われた不完全な儀式の結果か。","ENG":"Twenty years ago. The result of an incomplete ritual that took place in Lotus.","TWN":"20年前，在洛德斯發生的不完全儀式的產物。"},"stage":{"bg":"VARUNA_04_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"하지만 최근 바루나스트라는 로터스 관리국에 의해 토벌되었다고 들었다.","JPN":"しかし、ヴァルナストラはロータス管理局によってつい最近討伐されたはず。","ENG":"But I heard Varunastra was recently neutralized by the Lotus Administration.","TWN":"但我記得最近洛德斯管理局已經討伐過伐樓拿之艦了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그런데 어째서 네놈이 저것을 부릴 수 있는 거지?","JPN":"なのに、なぜ貴様があれを操れる？","ENG":"So how are you able to control that thing?","TWN":"那你們是怎麼稱呼那東西的？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"바루나스트라라…….","JPN":"ヴァルナストラか……","ENG":"Varunastra, you say...","TWN":"伐樓拿之艦啊……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"저것의 원래 이름은 바루나스트라가 아니다.","JPN":"あれの本来の名はヴァルナストラではない。","ENG":"That is not its original name.","TWN":"那並不是它原本的名字。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"신성을 매개로, 심연으로부터 <color=#ffd34c>이름 없는 존재</color>를 현실로 불러냈을 뿐이지.","JPN":"神聖を媒介とし、深淵から<color=#ffd34c>名もなき存在</color>を現実へ呼び出しただけだ。","ENG":"Using Divinity as a medium, I merely summoned a <color=#ffd34c>nameless being</color> from the abyss into reality.","TWN":"只是透過神性作為媒介，將深淵中的<color=#ffd34c>無名存在</color>召喚到現實罷了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"하지만 현실에는 그것을 감당할 그릇이 없었고.","JPN":"しかし現実にはそれに耐えられる器がない。","ENG":"But reality had no vessel capable of containing it.","TWN":"然而現實中並沒有能承載它的器皿。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그렇기에 격이 격하되어, 그곳에 있던 어느 함선과 승무원에 씌어 뒤섞여버린 끝에 저것이 탄생한 거다.","JPN":"ゆえに格が落ち、そこにあったとある艦船と乗務員に宿り、混ざりあった結果あれが誕生したのだ。","ENG":"So its rank degraded, and it fused with a ship and its crew that were present there, giving birth to that thing.","TWN":"所以被降格附著在當時的一艘艦船與船員身上，混雜後才誕生了那個東西。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"불행히도, 날 때부터 불완전한 기형아로 태어난 거지.","JPN":"不幸にも、生まれながらの不完全体というわけだ。","ENG":"Unfortunately, it was born a malformed abomination from the very start.","TWN":"不幸的是，它從誕生起就是不完整的畸形兒。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"우리 인간과 같이 말이야.","JPN":"我々人間のようにな。","ENG":"Much like us humans.","TWN":"就像我們人類一樣。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그렇기에 그날의 비극을 재현했다.","JPN":"だからこそあの日の悲劇を再現した。","ENG":"That is why I recreated the tragedy of that day.","TWN":"所以它重現了那一天的悲劇。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"네놈들이 이 고통스러운 현실에서 더욱 몸부림 칠 수 있도록.","JPN":"苦しみ溢れるこの現実で、貴様らが更に足掻けるように。","ENG":"So that you would struggle even more within this painful reality.","TWN":"為了讓你們在痛苦的現實中更加掙扎。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>그 남자</color>가 준 신성 파편을 이용해서 말이지.","JPN":"<color=#ffd34c>あの男</color>がくれた神聖の破片を利用して。","ENG":"By using the Divinity Fragment given to me by <color=#ffd34c>that man</color>.","TWN":"而這一切，是利用了<color=#ffd34c>那個男人</color>給我的神性碎片。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그 남자라면… 역시 교단의 우두머리인가?","JPN":"あの男……教団のトップのことだな？","ENG":"That man...? The leader of the cult, I presume?","TWN":"那個男人……果然是教團的首領嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"……계시의 때가 머지않았군.","JPN":"……啓示の時は近い。","ENG":"...The time of revelation draws near.","TWN":"……啟示的時刻就快到了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그럼, 무운을 빌겠다. 람다 스파타리.","JPN":"では、武運を祈る。ラムダ・スパタリー。","ENG":"Then allow me to wish you good luck, Lamda Spatari.","TWN":"那麼，祝你好運。蘭達．史派特。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L26_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"내가 놓칠 줄 알고……!","JPN":"逃がすか……！","ENG":"You think I would let you escape...!","TWN":"我怎麼可能放過你……！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L28_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_QM","text":{"KOREA":"법학부장님, 조심하세요……!","JPN":"法学部長、気をつけてください……！","ENG":"Ma'am, watch out...!","TWN":"法學院院長，小心……！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"이건 혈마법 결계……?","JPN":"これは、血魔法の結界……？","ENG":"A hemomancy barrier...?","TWN":"這是血魔法結界……？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_IMPACT_02"},{"id":"L33_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"다행이다. 다치신 곳은 없으세요?","JPN":"よかった。お怪我はありませんか？","ENG":"Thank goodness. You're not injured, are you?","TWN":"還好沒事，你沒受傷吧？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L35_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"늦었군, 종교학부. 그리고 어째서 끼어든 거지?","JPN":"遅かったな、宗教学部。それに、なぜ割り込んできた？","ENG":"You are late, Religion Department. And why are you interfering?","TWN":"你來晚了，宗教學院的。還有你為什麼插手？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"죄, 죄송해요… 저는 법학부장님께서 다치실까 봐…….","JPN":"す、すみません……法学部長が怪我しないようにと……","ENG":"I-I'm sorry... I was worried you might get hurt, ma'am...","TWN":"對、對不起……我只是擔心法學院院長會受傷……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"뭐야, 왜 구해줘도 난리야?","JPN":"助けてやったのになに文句言ってるの？","ENG":"What? Why are you making such a fuss even after being saved?","TWN":"搞什麼？救人還要被念喔？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"학부원이라면, 학부장에게 예의를 갖추도록.","JPN":"学部員なら、学部長に対する礼儀をわきまえるんだ。","ENG":"If you are a department member, show proper respect to a dean.","TWN":"身為學院成員，對學院院長要有基本禮儀。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"무슨 예의? 우리 또래 아니야? 굳이?","JPN":"礼儀？　同年代じゃないの？　その必要ある？","ENG":"Respect? We're about the same age, aren't we? Do we really need that?","TWN":"什麼禮儀？我們不是差不多年紀嗎？有這個必要嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"버, 법학부장님께 그게 무슨 말버릇이에요!","JPN":"ほ、法学部長に無礼ですよ！","ENG":"Th-that is no way to speak to the Dean of Law!","TWN":"你、你這樣對法學院院長太沒禮貌了！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"제발 눈치 좀 챙겨요. 이러다 우리 둘 다 죽는다고요!","JPN":"空気読んでください。このままだと私たち殺されますよ！","ENG":"Please read the room. At this rate, we're both going to get killed!","TWN":"拜託你識相一點，不然我們兩個都會死的！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"내가 왜? 내가 눈치 볼 사람은 쩐주밖에 없는데?","JPN":"なんで？　私が顔色窺うのは金をくれる人だけだよ？","ENG":"Why should I? The only person I watch my attitude around is the one paying me.","TWN":"我為什麼要？我只看出錢的臉色。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"*Sigh...*","TWN":"呼……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"사태가 시급하니, 예절교육은 나중으로 미루겠다.","JPN":"今は緊急事態だ、礼儀の教育は後で。","ENG":"Since the situation is urgent, I will postpone etiquette training for later.","TWN":"事態緊急，禮儀教育之後再說。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L4_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"우선은 학회 영지를 침범한 저 침식체를 섬멸하는 게 먼저니까.","JPN":"学会の領地に侵入したあの侵食体の殲滅が先だ。","ENG":"For now, eliminating that C.O. that has trespassed into the Society's estate takes priority.","TWN":"首要任務是殲滅那個侵入學會領地的侵蝕體。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};